export type SubjectKey = "russian" | "math" | "social";
export type QuestionMode = "diagnosis" | "session" | "both";

export type RussianTaskType =
  | "пунктуация"
  | "лексика"
  | "текст"
  | "грамматика"
  | "орфоэпия"
  | "орфография";

export type MathTaskType =
  | "уравнения"
  | "функции"
  | "геометрия"
  | "вероятность"
  | "текстовая_задача"
  | "вычисления"
  | "прогрессия"
  | "производная";

export type SocialTaskType =
  | "экономика"
  | "право"
  | "политика"
  | "социология"
  | "человек_и_общество"
  | "духовная_сфера";

export type TaskType = RussianTaskType | MathTaskType | SocialTaskType;

export type BankQuestion = {
  id: string;
  subject: SubjectKey;
  mode: QuestionMode;
  taskType: TaskType;
  topic: string;
  difficulty: "easy" | "medium" | "hard";
  prompt: string;
  options: string[];
  correctAnswer: string;
  explanation: string;
};

export type MiniVariant = {
  id: string;
  subject: SubjectKey;
  variantNumber: number;
  questions: BankQuestion[];
};

type QuestionInput = Omit<BankQuestion, "id" | "subject" | "mode" | "taskType">;

function inferRussianTaskType(topic: string): RussianTaskType {
  if (topic === "Пунктуация" || topic === "Сложное предложение") return "пунктуация";
  if (topic === "Лексика" || topic === "Паронимы" || topic === "Средства выразительности") return "лексика";
  if (topic === "Текст") return "текст";
  if (topic === "Орфоэпия" || topic === "Ударение") return "орфоэпия";
  if (topic === "Орфография") return "орфография";
  return "грамматика";
}

function inferMathTaskType(topic: string): MathTaskType {
  if (topic === "Функции" || topic === "Графики" || topic === "Тригонометрия") return "функции";
  if (topic === "Геометрия" || topic === "Планиметрия" || topic === "Стереометрия") return "геометрия";
  if (topic === "Вероятность") return "вероятность";
  if (topic === "Текстовые задачи") return "текстовая_задача";
  if (topic === "Последовательности") return "прогрессия";
  if (topic === "Производная") return "производная";
  if (topic === "Уравнения" || topic === "Неравенства") return "уравнения";
  return "вычисления";
}

function inferSocialTaskType(topic: string): SocialTaskType {
  if (topic === "Экономика") return "экономика";
  if (topic === "Право") return "право";
  if (topic === "Политика") return "политика";
  if (topic === "Социология" || topic === "Социальные отношения") return "социология";
  if (topic === "Человек и общество") return "человек_и_общество";
  return "духовная_сфера";
}

function inferTaskType(subject: SubjectKey, topic: string): TaskType {
  if (subject === "math") return inferMathTaskType(topic);
  if (subject === "social") return inferSocialTaskType(topic);
  return inferRussianTaskType(topic);
}

function createQuestions(subject: SubjectKey, mode: QuestionMode, entries: QuestionInput[]) {
  return entries.map((entry, index) => ({
    id: `${subject}-${mode}-${index + 1}`,
    subject,
    mode,
    taskType: inferTaskType(subject, entry.topic),
    ...entry,
  }));
}

function shuffle<T>(items: T[]) {
  const copy = [...items];

  for (let index = copy.length - 1; index > 0; index -= 1) {
    const randomIndex = Math.floor(Math.random() * (index + 1));
    [copy[index], copy[randomIndex]] = [copy[randomIndex], copy[index]];
  }

  return copy;
}

