function createMiniVariants(subject: SubjectKey, questions: BankQuestion[]) {
  const questionsPerVariant = 12;

  return [0, 1, 2].map((index) => ({
    id: `${subject}-mini-variant-${index + 1}`,
    subject,
    variantNumber: index + 1,
    questions: questions.slice(index * questionsPerVariant, index * questionsPerVariant + questionsPerVariant),
  }));
}

export const QUESTION_BANK: BankQuestion[] = [
  ...russianDiagnosis,
  ...russianSession,
  ...mathDiagnosis,
  ...mathSession,
  ...socialDiagnosis,
  ...socialSession,
];

export const MINI_VARIANTS: MiniVariant[] = [
  ...createMiniVariants("russian", russianSession),
  ...createMiniVariants("math", mathSession),
  ...createMiniVariants("social", socialSession),
];

export function getQuestionsBySubject(subject: SubjectKey, mode: QuestionMode) {
  return QUESTION_BANK.filter(
    (question) => question.subject === subject && (question.mode === mode || question.mode === "both"),
  );
}

export function getDiagnosisQuestions(subject: SubjectKey, count = 6) {
  return shuffle(getQuestionsBySubject(subject, "diagnosis")).slice(0, count);
}

export function getMiniVariantsBySubject(subject: SubjectKey) {
  return MINI_VARIANTS.filter((variant) => variant.subject === subject);
}

export function getMiniVariantById(variantId: string) {
  return MINI_VARIANTS.find((variant) => variant.id === variantId) ?? null;
}

export function buildSessionQuestions(
  subject: SubjectKey,
  options: { count?: number; seenIds?: string[]; incorrectIds?: string[] } = {},
) {
  const count = options.count ?? 9;
  const seenIds = new Set(options.seenIds ?? []);
  const incorrectIds = new Set(options.incorrectIds ?? []);
  const allQuestions = shuffle(getQuestionsBySubject(subject, "session"));

  const unseenIncorrect = allQuestions.filter(
    (question) => incorrectIds.has(question.id) && !seenIds.has(question.id),
  );
  const unseenRegular = allQuestions.filter(
    (question) => !incorrectIds.has(question.id) && !seenIds.has(question.id),
  );
  const seenIncorrect = allQuestions.filter(
    (question) => incorrectIds.has(question.id) && seenIds.has(question.id),
  );
  const seenRegular = allQuestions.filter(
    (question) => !incorrectIds.has(question.id) && seenIds.has(question.id),
  );

  const picked: BankQuestion[] = [];
  const pickedIds = new Set<string>();

  function takeFrom(pool: BankQuestion[], limit: number) {
    for (const question of pool) {
      if (picked.length >= limit) break;
      if (pickedIds.has(question.id)) continue;
      picked.push(question);
      pickedIds.add(question.id);
    }
  }

  if (incorrectIds.size > 0) {
    takeFrom(unseenIncorrect, 1);
    if (picked.length === 0) {
      takeFrom(seenIncorrect, 1);
    }
  }

  takeFrom(unseenRegular, count);
  takeFrom(unseenIncorrect, count);
  takeFrom(seenRegular, count);
  takeFrom(seenIncorrect, count);

  return picked.slice(0, count);
}
